async function seed() {
  console.log(`Seeding ${payloads.length} payloads...`);
  
  // Clear existing payloads
  await db.delete(payloadsTable);
  
  // Insert in batches of 50
  const batchSize = 50;
  for (let i = 0; i < payloads.length; i += batchSize) {
    const batch = payloads.slice(i, i + batchSize);
    await db.insert(payloadsTable).values(batch);
    console.log(`Inserted batch ${Math.floor(i/batchSize)+1}/${Math.ceil(payloads.length/batchSize)} (${i + batch.length}/${payloads.length})`);
  }
  
  console.log("Seeding complete!");
  process.exit(0);
}

seed().catch(e => { console.error(e); process.exit(1); });
